    struct Hashmap *h = malloc(sizeof(struct Hashmap));
    h->buckets = calloc(capacity, sizeof(struct BucketNode *));
    h->size = 0;
    h->cap = capacity;
    h->hash = fnva1;
    h->equals = equal_key;
    return h;
