    struct BucketNode **new_buckets =
        calloc(h->cap * 2, sizeof(struct BucketNode *));
    for (int i = 0; i < h->cap; i++) {
        if (h->buckets[i] != NULL) {
            struct BucketNode *b = h->buckets[i];
            unsigned a = h->hash(b->key) % h->cap;
            new_buckets[a] = b;
        }
    }
    h->buckets = new_buckets;
    h->cap = h->cap * 2;
}
