        return TT_ELSE;
    } else if (STREQ(contents, "extern")) {
        return TT_EXTERN;
    } else if (STREQ(contents, "float")) {
        return TT_FLOAT;
    } else if (STREQ(contents, "for")) {
        return TT_FOR;
    } else if (STREQ(contents, "goto")) {
        return TT_GOTO;
    } else if (STREQ(contents, "int")) {
        return TT_INT;
    } else if (STREQ(contents, "if")) {
        return TT_IF;
    } else if (STREQ(contents, "long")) {
        return TT_LONG;
    } else if (STREQ(contents, "return")) {
        return TT_RETURN;
    } else if (STREQ(contents, "register")) {
        return TT_REGISTER;
    } else if (STREQ(contents, "struct")) {
        return TT_STRUCT;
    } else if (STREQ(contents, "signed")) {
        return TT_SIGNED;
    } else if (STREQ(contents, "sizeof")) {
        return TT_SIZEOF;
    } else if (STREQ(contents, "static")) {
        return TT_STATIC;
    } else if (STREQ(contents, "short")) {
        return TT_SHORT;
    } else if (STREQ(contents, "switch")) {
        return TT_SWITCH;
    } else if (STREQ(contents, "typedef")) {
        return TT_TYPEDEF;
    } else if (STREQ(contents, "union")) {
        return TT_UNION;
    } else if (STREQ(contents, "unsigned")) {
        return TT_UNSIGNED;
    } else if (STREQ(contents, "void")) {
        return TT_VOID;
    } else if (STREQ(contents, "volatile")) {
        return TT_VOLATILE;
    } else if (STREQ(contents, "while")) {
        return TT_WHILE;
    } else if (STREQ(contents, "&&")) {
        return TT_LAND;
    } else if (STREQ(contents, "||")) {
        return TT_LOR;
    } else if (STREQ(contents, "-=")) {
        return TT_DEC;
    } else if (STREQ(contents, "+=")) {
        return TT_INC;
    } else if (STREQ(contents, "++")) {
        return TT_PLUSPLUS;
    } else if (STREQ(contents, "--")) {
        return TT_MINUSMINUS;
    } else if (STREQ(contents, "/=")) {
        return TT_DIVEQ;
    } else if (STREQ(contents, "*=")) {
        return TT_MULEQ;
    } else if (STREQ(contents, "%=")) {
        return TT_MODEQ;
    } else if (STREQ(contents, "&=")) {
        return TT_BANDEQ;
    } else if (STREQ(contents, "|=")) {
        return TT_BOREQ;
    } else if (STREQ(contents, "&&=")) {
        return TT_LANDEQ;
    } else if (STREQ(contents, "||=")) {
        return TT_LOREQ;
    } else if (STREQ(contents, "<=")) {
        return TT_LESSEQ;
    } else if (STREQ(contents, ">=")) {
        return TT_GREATEREQ;
    } else if (STREQ(contents, "<<")) {
        return TT_LEFTSHIFT;
    } else if (STREQ(contents, ">>")) {
        return TT_RIGHTSHIFT;
    } else if (STREQ(contents, "==")) {
        return TT_EQUALS;
    } else if (STREQ(contents, "^=")) {
        return TT_XOREQ;
    } else if (STREQ(contents, "->")) {
        return TT_POINT;
    } else if (STREQ(contents, "<<=")) {
        return TT_LEFTSHIFTEQUALS;
    } else if (STREQ(contents, ">>=")) {
        return TT_RIGHTSHIFTEQUALS;
    } else if (STREQ(contents, "!=")) {
        return TT_NOTEQ;
    }

    int all_numeric = 1;
    int count_fs = 0;
    int count_us = 0;
    int i;
    if (contents == NULL) {
        return TT_NO_TOKEN;
    }

    for (i = 0; contents[i] != '\0'; i++) {
        char c = contents[i];

        if (c == '.') {
            return TT_LITERAL;
        }

        if (c == 'f') {
            count_fs++;
        }

        if (c == 'u') {
            count_us++;
        }

        if ((c > '9' || c < '0') && c != 'u') {
            all_numeric = 0;
        }
        if (c == '\'' || c == '"') {
            return TT_LITERAL;
        }
    }
    if (all_numeric) {

        if (count_us == 1 && contents[i - 1] == 'u') {
            return TT_LITERAL;
        }

        if (count_us == 0) {
            return TT_LITERAL;
        }
    }
    return TT_IDENTIFIER;
}
TokenType ttype_from_string(const char *contents) {
    int len;
    len = strlen(contents);

    if (len == 1) {
        TokenType token = ttype_one_char(contents[0]);
		return token;
    }
    return ttype_many_chars(contents);
}
static const char *ttype_names[] = {
