#include "list.h"
#include <stdlib.h> 
#include <util/out.h>
typedef struct ListBlock {
    void* * array;
    int size, full;
    struct ListBlock* next;
} ListBlock;
struct List {
    ListBlock *head, *tail;
    int blocksize;
};
List* create_list(int blocksize) {
    List* l = malloc(sizeof(List));
    if (!l) {
        PRINT_ERROR("internal: failed to allocate memory");
        return NULL;
    }
    l->blocksize = blocksize;
    l->head = l->tail = NULL;
    return l;
}
int destroy_list(List* l) {

    ListBlock *lb = l->head, *next;
    while (lb) {
        next = lb->next;
        free(lb->array);
        free(lb);
        lb = next;
    }
    free(l);
    return 0;
}
static int lfind_index(List* l, ListBlock** lb, int* i) {
    *lb = l->head;
    if (*i < 0) {
        PRINT_ERROR("internal: list index was negative (%d)", *i);
        return -1;
    }


    while (*i >= (*lb)->size) {
        if (lb) {
            *lb = (*lb)->next;
            *i -= (*lb)->size;
        } else {
            PRINT_ERROR("internal: list index %d out of bounds", *i);
            return -1;
        }
    }
    return 0;
}
void* lget_element(List* l, int index) {
    int i = index;
    ListBlock* lb;
    lfind_index(l, &lb, &i);

    if (i >= lb->full) {
        PRINT_ERROR("internal: list index %d out of bounds", index);
        return NULL;
    }
    return lb->array[i];
}
int lset_element(List* l, int index, void* value) {
    int i = index, ret;
    ListBlock* lb;
    if ((ret = lfind_index(l, &lb, &i))) return ret;

    if (i >= lb->full) {
        PRINT_ERROR("internal: list index %d out of bounds", index);
        return -1;
    }
    lb->array[i] = value;
    return 0;
}
static ListBlock* new_block(List* l) {
    ListBlock* lb = malloc(sizeof(ListBlock));
    if (lb == NULL) return NULL;
    lb->array = malloc(l->blocksize * sizeof(void *));
    if (lb->array == NULL) {
        free(lb);
        return NULL;
    }
    lb->full = 0;
    lb->size = l->blocksize;
    lb->next = NULL;
    return lb;
}
int ladd_element(List* l, void* element) {

    if (l->head == NULL) {
        l->tail = new_block(l);
        l->head = l->tail;
    }

    ListBlock* lb = l->tail;
    if (lb->full < lb->size) {
        lb->array[lb->full++] = element;
    } else {

        l->tail = new_block(l);
        lb->next = l->tail;
        lb = lb->next;
        lb->array[lb->full++] = element;
    }
    return 0;
}
int literate(List* l, int (*fn)(void*)) {
    ListBlock* lb = l->head;
    int acc = 0;
    while (lb != NULL) {
        for (int i = 0; i < lb->full; ++i) {
            acc += fn(lb->array[i]);
        }
        lb = lb->next;
    }
    return acc;
}
